class MyModel(models.Model):
    _name = 'my.model'

    name = fields.Char(required=True)

    _sql_constraints = [
        ('name_unique', 'unique(name)', 'Le nom doit être unique.')
    ]

    @api.constrains('name')
    def _check_name(self):
        for rec in self:
            if not rec.name.strip():
                raise ValidationError('Le nom ne peut pas être vide.')
